import{_ as e,o,c as a,a2 as n}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"LLM APIs and Protocols for Coding Agents","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/llm-apis-and-protocols/index.md","filePath":"research/concepts/llm-apis-and-protocols/index.md"}'),s={name:"research/concepts/llm-apis-and-protocols/index.md"};function r(i,t,d,l,c,p){return o(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="llm-apis-and-protocols-for-coding-agents" tabindex="-1">LLM APIs and Protocols for Coding Agents <a class="header-anchor" href="#llm-apis-and-protocols-for-coding-agents" aria-label="Permalink to &quot;LLM APIs and Protocols for Coding Agents&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>Large Language Model APIs are the foundational layer upon which all modern coding agents are built. Whether it&#39;s GitHub Copilot generating inline suggestions, Cursor composing multi-file edits, or an autonomous SWE-agent resolving GitHub issues end-to-end, every one of these systems ultimately communicates with an LLM through an HTTP API.</p><p>Understanding these APIs deeply matters for several reasons:</p><ol><li><strong>Architecture decisions</strong> — The capabilities and constraints of each API directly shape what a coding agent can and cannot do. Tool-calling support, context window size, streaming behavior, and structured output features all influence agent design.</li><li><strong>Cost optimization</strong> — LLM API calls are the primary cost center for coding agents. Understanding token economics, prompt caching, and batch APIs enables building agents that are economically viable.</li><li><strong>Reliability engineering</strong> — Rate limits, timeout behaviors, error codes, and retry strategies differ across providers. Production coding agents must handle these gracefully.</li><li><strong>Performance</strong> — Streaming vs. non-streaming, parallel tool calls, and speculative decoding all affect the perceived latency of an agent. Understanding the wire protocol enables optimization.</li><li><strong>Provider flexibility</strong> — The best coding agents are not locked to a single provider. Understanding the common patterns and key differences across APIs enables multi-provider architectures.</li></ol><p>This folder contains deep-dive research into every major LLM API relevant to building coding agents.</p><hr><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Topic</th><th>Description</th></tr></thead><tbody><tr><td><a href="./chat-completions.html">chat-completions.md</a></td><td>OpenAI Chat Completions API</td><td>The foundational API that established the chat paradigm. Full request/response schema, streaming, tool calling, structured outputs.</td></tr><tr><td><a href="./responses-api.html">responses-api.md</a></td><td>OpenAI Responses API</td><td>OpenAI&#39;s next-generation stateful API with built-in tools (web search, file search, code interpreter), multi-turn state management.</td></tr><tr><td><a href="./messages-api.html">messages-api.md</a></td><td>Anthropic Messages API</td><td>Anthropic&#39;s Claude API — content blocks, extended thinking, tool use, prompt caching, and the differences from OpenAI&#39;s approach.</td></tr><tr><td><a href="./function-calling.html">function-calling.md</a></td><td>Function/Tool Calling Deep-Dive</td><td>Cross-provider comparison of tool calling: JSON schema definitions, parallel calls, forced tool use, and agent loop patterns.</td></tr><tr><td><a href="./extended-thinking.html">extended-thinking.md</a></td><td>Extended Thinking &amp; Reasoning</td><td>How reasoning models (o3, o4-mini, Claude with extended thinking) expose chain-of-thought via APIs, budget tokens, and streaming thinking.</td></tr><tr><td><a href="./embeddings.html">embeddings.md</a></td><td>Embeddings APIs</td><td>Text embedding endpoints for RAG-based coding agents — OpenAI, Voyage, Cohere embeddings for code search and retrieval.</td></tr><tr><td><a href="./batch-api.html">batch-api.md</a></td><td>Batch &amp; Async APIs</td><td>Batch processing endpoints for offline workloads — OpenAI Batch API, Anthropic Message Batches, cost savings and use cases.</td></tr><tr><td><a href="./rate-limits-and-retries.html">rate-limits-and-retries.md</a></td><td>Rate Limits &amp; Retry Strategies</td><td>Rate limit headers, exponential backoff, retry-after, circuit breakers, and production resilience patterns.</td></tr><tr><td><a href="./agent-comparison.html">agent-comparison.md</a></td><td>Coding Agent API Usage Comparison</td><td>How major coding agents (Copilot, Cursor, Cline, Aider, SWE-agent) use these APIs in practice.</td></tr></tbody></table><hr><h2 id="the-landscape-of-llm-api-providers" tabindex="-1">The Landscape of LLM API Providers <a class="header-anchor" href="#the-landscape-of-llm-api-providers" aria-label="Permalink to &quot;The Landscape of LLM API Providers&quot;">​</a></h2><h3 id="tier-1-frontier-model-providers" tabindex="-1">Tier 1: Frontier Model Providers <a class="header-anchor" href="#tier-1-frontier-model-providers" aria-label="Permalink to &quot;Tier 1: Frontier Model Providers&quot;">​</a></h3><p>These companies train and serve their own frontier models behind proprietary APIs:</p><p><strong>OpenAI</strong></p><ul><li>APIs: Chat Completions (<code>/v1/chat/completions</code>), Responses (<code>/v1/responses</code>), Embeddings, Audio, Images</li><li>Models: GPT-4o, GPT-4o-mini, GPT-4-turbo, o3, o4-mini, o3-mini</li><li>Key differentiator: Largest ecosystem, most third-party integrations, industry-standard API format</li><li>SDKs: <code>openai</code> (Python), <code>openai</code> (Node.js/TypeScript)</li></ul><p><strong>Anthropic</strong></p><ul><li>APIs: Messages (<code>/v1/messages</code>), Message Batches</li><li>Models: Claude Sonnet 4, Claude Opus 4, Claude Haiku 3.5, Claude 3 Opus</li><li>Key differentiator: Extended thinking for complex reasoning, prompt caching, superior long-context performance</li><li>SDKs: <code>anthropic</code> (Python), <code>@anthropic-ai/sdk</code> (TypeScript)</li></ul><p><strong>Google DeepMind</strong></p><ul><li>APIs: Gemini API (<code>/v1/models/{model}:generateContent</code>), Vertex AI</li><li>Models: Gemini 2.5 Pro, Gemini 2.5 Flash, Gemini 2.0 Flash</li><li>Key differentiator: Massive context windows (1M+ tokens), native multimodal, competitive pricing</li><li>SDKs: <code>google-genai</code> (Python), <code>@google/genai</code> (TypeScript)</li></ul><h3 id="tier-2-inference-providers-open-source-model-hosts" tabindex="-1">Tier 2: Inference Providers (Open-Source Model Hosts) <a class="header-anchor" href="#tier-2-inference-providers-open-source-model-hosts" aria-label="Permalink to &quot;Tier 2: Inference Providers (Open-Source Model Hosts)&quot;">​</a></h3><p>These providers serve open-weight models, often with OpenAI-compatible APIs:</p><ul><li><strong>Together AI</strong> — Llama, Mixtral, Qwen, DeepSeek with OpenAI-compatible API</li><li><strong>Fireworks AI</strong> — Optimized inference for open models, function calling support</li><li><strong>Groq</strong> — Ultra-low-latency inference using custom LPU hardware</li><li><strong>AWS Bedrock</strong> — Managed access to Claude, Llama, Mistral, and other models</li><li><strong>Azure OpenAI</strong> — Microsoft-hosted OpenAI models with enterprise compliance</li><li><strong>DeepSeek</strong> — DeepSeek-V3, DeepSeek-R1, competitive pricing, OpenAI-compatible</li></ul><h3 id="tier-3-local-self-hosted" tabindex="-1">Tier 3: Local/Self-Hosted <a class="header-anchor" href="#tier-3-local-self-hosted" aria-label="Permalink to &quot;Tier 3: Local/Self-Hosted&quot;">​</a></h3><ul><li><strong>Ollama</strong> — Local model serving with OpenAI-compatible API</li><li><strong>vLLM</strong> — High-throughput serving engine, OpenAI-compatible server</li><li><strong>llama.cpp</strong> — CPU/GPU inference with HTTP server mode</li><li><strong>LM Studio</strong> — Desktop app with local API server</li></ul><hr><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h2><h3 id="the-chat-completions-paradigm" tabindex="-1">The Chat Completions Paradigm <a class="header-anchor" href="#the-chat-completions-paradigm" aria-label="Permalink to &quot;The Chat Completions Paradigm&quot;">​</a></h3><p>The modern LLM API interaction model was established by OpenAI&#39;s Chat Completions API in March 2023 and has since become the de facto standard. The core abstraction is a <strong>conversation as a sequence of messages</strong>, where each message has a <strong>role</strong> and <strong>content</strong>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>system:    &quot;You are a helpful coding assistant...&quot;</span></span>
<span class="line"><span>user:      &quot;Write a function that sorts a list&quot;</span></span>
<span class="line"><span>assistant: &quot;Here&#39;s a Python function that sorts a list...&quot;</span></span>
<span class="line"><span>user:      &quot;Make it handle None values&quot;</span></span>
<span class="line"><span>assistant: &quot;Here&#39;s the updated function...&quot;</span></span></code></pre></div><p>This paradigm replaced the earlier &quot;completions&quot; API where you sent a single text prompt and got a continuation. The chat format provides structure that enables:</p><ul><li><strong>System prompts</strong> for persistent instructions and persona</li><li><strong>Multi-turn conversations</strong> with preserved context</li><li><strong>Tool calling</strong> via structured assistant messages with tool invocations</li><li><strong>Clear delineation</strong> between user input and model output</li></ul><h3 id="message-roles" tabindex="-1">Message Roles <a class="header-anchor" href="#message-roles" aria-label="Permalink to &quot;Message Roles&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Role</th><th>Purpose</th><th>Provider Support</th></tr></thead><tbody><tr><td><code>system</code></td><td>Sets behavior, persona, and instructions</td><td>OpenAI, Google (as <code>system_instruction</code>), Anthropic (as top-level <code>system</code> param)</td></tr><tr><td><code>user</code></td><td>Human input — text, images, files</td><td>All providers</td></tr><tr><td><code>assistant</code></td><td>Model output — text, tool calls, refusals</td><td>All providers</td></tr><tr><td><code>tool</code></td><td>Results from tool/function execution</td><td>OpenAI, Google, Anthropic (as <code>tool_result</code> role)</td></tr><tr><td><code>developer</code></td><td>OpenAI-specific: trusted instructions from the application developer</td><td>OpenAI only (Responses API)</td></tr></tbody></table><h3 id="token-economics" tabindex="-1">Token Economics <a class="header-anchor" href="#token-economics" aria-label="Permalink to &quot;Token Economics&quot;">​</a></h3><p>Tokens are the atomic units of LLM processing and billing. Understanding tokenization is critical for cost management:</p><ul><li><strong>1 token ≈ 4 characters</strong> in English (approximately 0.75 words)</li><li><strong>Code tokenizes differently</strong> — variable names, operators, and whitespace each consume tokens</li><li><strong>Input tokens</strong> (prompt) are cheaper than <strong>output tokens</strong> (completion) — typically 2-4x cheaper</li><li><strong>Cached input tokens</strong> are even cheaper — typically 50% of standard input cost</li><li>Models have a <strong>context window</strong> (max total tokens) and <strong>max output tokens</strong> (max generation length)</li></ul><h3 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h3><p>All major APIs support server-sent events (SSE) for streaming responses token-by-token:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>data: {&quot;choices&quot;:[{&quot;delta&quot;:{&quot;content&quot;:&quot;Hello&quot;}}]}</span></span>
<span class="line"><span>data: {&quot;choices&quot;:[{&quot;delta&quot;:{&quot;content&quot;:&quot; world&quot;}}]}</span></span>
<span class="line"><span>data: [DONE]</span></span></code></pre></div><p>Streaming is essential for coding agents because:</p><ul><li>Users see output as it&#39;s generated, reducing perceived latency</li><li>Agents can begin processing tool calls before the full response completes</li><li>Long generations (multi-file edits) would otherwise have unacceptable time-to-first-token</li></ul><hr><h2 id="summary-comparison-of-major-apis" tabindex="-1">Summary Comparison of Major APIs <a class="header-anchor" href="#summary-comparison-of-major-apis" aria-label="Permalink to &quot;Summary Comparison of Major APIs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>OpenAI Chat Completions</th><th>OpenAI Responses API</th><th>Anthropic Messages</th><th>Google Gemini</th></tr></thead><tbody><tr><td><strong>Endpoint</strong></td><td><code>POST /v1/chat/completions</code></td><td><code>POST /v1/responses</code></td><td><code>POST /v1/messages</code></td><td><code>POST /v1/models/{m}:generateContent</code></td></tr><tr><td><strong>Message format</strong></td><td><code>messages[]</code> with role/content</td><td><code>input</code> (string or items[])</td><td><code>messages[]</code> with role/content blocks</td><td><code>contents[]</code> with role/parts</td></tr><tr><td><strong>System prompt</strong></td><td><code>system</code> role in messages</td><td><code>instructions</code> param</td><td>Top-level <code>system</code> param</td><td><code>system_instruction</code> param</td></tr><tr><td><strong>Tool calling</strong></td><td><code>tools[]</code> + <code>tool_choice</code></td><td>Built-in tools + custom <code>tools[]</code></td><td><code>tools[]</code> + <code>tool_choice</code></td><td><code>tools[]</code> + <code>tool_config</code></td></tr><tr><td><strong>Structured output</strong></td><td><code>response_format</code> with JSON schema</td><td><code>text.format</code> with JSON schema</td><td>Partial (via tool_use trick)</td><td><code>response_mime_type</code> + schema</td></tr><tr><td><strong>Streaming</strong></td><td>SSE with <code>delta</code> objects</td><td>SSE with typed events</td><td>SSE with typed events</td><td>SSE with candidates</td></tr><tr><td><strong>Thinking/reasoning</strong></td><td><code>reasoning_effort</code> param (o-series)</td><td><code>reasoning</code> param</td><td><code>thinking</code> with <code>budget_tokens</code></td><td><code>thinking_config</code> with budget</td></tr><tr><td><strong>Prompt caching</strong></td><td>Automatic (zero config)</td><td>Automatic</td><td><code>cache_control</code> breakpoints</td><td>Context caching API</td></tr><tr><td><strong>Stateful</strong></td><td>No (client manages state)</td><td>Yes (server stores conversation)</td><td>No (client manages state)</td><td>No (client manages state)</td></tr><tr><td><strong>Max context</strong></td><td>128K-200K tokens</td><td>200K tokens</td><td>200K tokens</td><td>1M-2M tokens</td></tr><tr><td><strong>Parallel tool calls</strong></td><td>Yes (default)</td><td>Yes</td><td>Yes (tool_choice <code>any</code>)</td><td>Yes</td></tr></tbody></table><hr><h2 id="evolution-from-completions-to-agentic-apis" tabindex="-1">Evolution: From Completions to Agentic APIs <a class="header-anchor" href="#evolution-from-completions-to-agentic-apis" aria-label="Permalink to &quot;Evolution: From Completions to Agentic APIs&quot;">​</a></h2><p>The LLM API landscape has evolved through several distinct phases:</p><h3 id="phase-1-text-completions-2020-2023" tabindex="-1">Phase 1: Text Completions (2020-2023) <a class="header-anchor" href="#phase-1-text-completions-2020-2023" aria-label="Permalink to &quot;Phase 1: Text Completions (2020-2023)&quot;">​</a></h3><ul><li>Simple prompt-in, completion-out</li><li><code>POST /v1/completions</code> with a text <code>prompt</code></li><li>No conversation structure, no roles</li><li>Agent developers had to format conversations manually</li></ul><h3 id="phase-2-chat-completions-2023-2024" tabindex="-1">Phase 2: Chat Completions (2023-2024) <a class="header-anchor" href="#phase-2-chat-completions-2023-2024" aria-label="Permalink to &quot;Phase 2: Chat Completions (2023-2024)&quot;">​</a></h3><ul><li>Structured conversations with roles</li><li><code>POST /v1/chat/completions</code> with <code>messages[]</code></li><li>Function calling added (June 2023), later renamed to tool calling</li><li>JSON mode for structured output</li><li>This became the universal standard — even non-OpenAI providers adopted this format</li></ul><h3 id="phase-3-agentic-apis-2024-present" tabindex="-1">Phase 3: Agentic APIs (2024-present) <a class="header-anchor" href="#phase-3-agentic-apis-2024-present" aria-label="Permalink to &quot;Phase 3: Agentic APIs (2024-present)&quot;">​</a></h3><ul><li>Server-side conversation state (OpenAI Responses API)</li><li>Built-in tools (web search, code execution, file search)</li><li>Extended thinking and reasoning tokens</li><li>Multi-step agent loops with automatic tool execution</li><li>Prompt caching across turns</li></ul><h3 id="phase-4-emerging-patterns" tabindex="-1">Phase 4: Emerging Patterns <a class="header-anchor" href="#phase-4-emerging-patterns" aria-label="Permalink to &quot;Phase 4: Emerging Patterns&quot;">​</a></h3><ul><li><strong>Model Context Protocol (MCP)</strong> — Anthropic&#39;s open standard for tool integration</li><li><strong>Computer Use / Browser Use</strong> — Models that can interact with desktop and web UIs</li><li><strong>Multi-agent orchestration</strong> — APIs designed for agent-to-agent communication</li><li><strong>Real-time APIs</strong> — WebSocket-based voice and video interaction</li></ul><hr><h2 id="how-coding-agents-choose-which-api-to-use" tabindex="-1">How Coding Agents Choose Which API to Use <a class="header-anchor" href="#how-coding-agents-choose-which-api-to-use" aria-label="Permalink to &quot;How Coding Agents Choose Which API to Use&quot;">​</a></h2><p>Coding agents typically select their LLM API based on:</p><ol><li><strong>Task complexity</strong> → Simple autocomplete uses fast/cheap models (GPT-4o-mini, Haiku); complex multi-file refactoring uses frontier models (Claude Sonnet, GPT-4o, o3)</li><li><strong>Latency requirements</strong> → Inline completion needs &lt;500ms time-to-first-token; background tasks can tolerate seconds</li><li><strong>Context length</strong> → Large codebases may need 100K+ token contexts; Gemini&#39;s 1M+ window is advantageous here</li><li><strong>Tool calling needs</strong> → Agents with many tools benefit from strong tool-calling models</li><li><strong>Cost constraints</strong> → High-volume usage favors cheaper models or batch APIs</li><li><strong>Compliance</strong> → Enterprise deployments may require Azure OpenAI or AWS Bedrock</li></ol><hr><h2 id="common-patterns-across-all-apis" tabindex="-1">Common Patterns Across All APIs <a class="header-anchor" href="#common-patterns-across-all-apis" aria-label="Permalink to &quot;Common Patterns Across All APIs&quot;">​</a></h2><h3 id="request-response" tabindex="-1">Request/Response <a class="header-anchor" href="#request-response" aria-label="Permalink to &quot;Request/Response&quot;">​</a></h3><p>Every LLM API follows this basic pattern:</p><ol><li>Send an HTTP POST request with a JSON body containing the model name, messages, and parameters</li><li>Receive a JSON response with the model&#39;s output, token usage, and metadata</li><li>For tool-calling flows, process tool calls and send results back in a follow-up request</li></ol><h3 id="streaming-with-server-sent-events-sse" tabindex="-1">Streaming with Server-Sent Events (SSE) <a class="header-anchor" href="#streaming-with-server-sent-events-sse" aria-label="Permalink to &quot;Streaming with Server-Sent Events (SSE)&quot;">​</a></h3><p>All providers use SSE for streaming:</p><ul><li>Set <code>stream: true</code> in the request</li><li>Response uses <code>Content-Type: text/event-stream</code></li><li>Each event is prefixed with <code>data: </code> followed by a JSON object</li><li>A final sentinel (<code>data: [DONE]</code> for OpenAI, <code>event: message_stop</code> for Anthropic) signals completion</li></ul><h3 id="tool-function-calling" tabindex="-1">Tool/Function Calling <a class="header-anchor" href="#tool-function-calling" aria-label="Permalink to &quot;Tool/Function Calling&quot;">​</a></h3><p>The universal tool-calling pattern:</p><ol><li>Define tools as JSON objects with name, description, and parameter schema</li><li>Send the tools array alongside messages</li><li>Model responds with tool call(s) — function name and arguments</li><li>Agent executes the function and returns results</li><li>Model generates a final response incorporating tool results</li></ol><h3 id="structured-output" tabindex="-1">Structured Output <a class="header-anchor" href="#structured-output" aria-label="Permalink to &quot;Structured Output&quot;">​</a></h3><p>Force the model to produce valid JSON matching a schema:</p><ul><li>OpenAI: <code>response_format: { type: &quot;json_schema&quot;, json_schema: { ... } }</code></li><li>Anthropic: Use a tool with the desired schema and force it via <code>tool_choice</code></li><li>Google: <code>response_mime_type: &quot;application/json&quot;</code> + <code>response_schema</code></li></ul><hr><h2 id="authentication-patterns" tabindex="-1">Authentication Patterns <a class="header-anchor" href="#authentication-patterns" aria-label="Permalink to &quot;Authentication Patterns&quot;">​</a></h2><h3 id="api-keys-most-common" tabindex="-1">API Keys (Most Common) <a class="header-anchor" href="#api-keys-most-common" aria-label="Permalink to &quot;API Keys (Most Common)&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Authorization: Bearer sk-...</span></span></code></pre></div><p>Simple, stateless, and used by OpenAI, Anthropic, Google, and most inference providers. Keys are typically scoped to an organization/project.</p><h3 id="oauth-2-0-enterprise" tabindex="-1">OAuth 2.0 (Enterprise) <a class="header-anchor" href="#oauth-2-0-enterprise" aria-label="Permalink to &quot;OAuth 2.0 (Enterprise)&quot;">​</a></h3><p>Azure OpenAI and Google Vertex AI support OAuth with service accounts and managed identities for enterprise deployments where API keys are insufficient.</p><h3 id="environment-variable-conventions" tabindex="-1">Environment Variable Conventions <a class="header-anchor" href="#environment-variable-conventions" aria-label="Permalink to &quot;Environment Variable Conventions&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CDD6F4;">OPENAI_API_KEY</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">sk-...</span></span>
<span class="line"><span style="color:#CDD6F4;">ANTHROPIC_API_KEY</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">sk-ant-...</span></span>
<span class="line"><span style="color:#CDD6F4;">GOOGLE_API_KEY</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">AI...</span></span></code></pre></div><hr><h2 id="sdk-ecosystem" tabindex="-1">SDK Ecosystem <a class="header-anchor" href="#sdk-ecosystem" aria-label="Permalink to &quot;SDK Ecosystem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Provider</th><th>Python SDK</th><th>TypeScript SDK</th><th>API Compatibility</th></tr></thead><tbody><tr><td>OpenAI</td><td><code>openai</code> (PyPI)</td><td><code>openai</code> (npm)</td><td>Reference implementation</td></tr><tr><td>Anthropic</td><td><code>anthropic</code> (PyPI)</td><td><code>@anthropic-ai/sdk</code> (npm)</td><td>Unique API format</td></tr><tr><td>Google</td><td><code>google-genai</code> (PyPI)</td><td><code>@google/genai</code> (npm)</td><td>Unique API format</td></tr><tr><td>Azure OpenAI</td><td><code>openai</code> (with azure config)</td><td><code>openai</code> (with azure config)</td><td>OpenAI-compatible</td></tr><tr><td>Together AI</td><td><code>together</code> or <code>openai</code></td><td><code>openai</code> (with base URL)</td><td>OpenAI-compatible</td></tr><tr><td>Fireworks</td><td><code>openai</code> (with base URL)</td><td><code>openai</code> (with base URL)</td><td>OpenAI-compatible</td></tr><tr><td>Ollama</td><td><code>openai</code> (with base URL)</td><td><code>openai</code> (with base URL)</td><td>OpenAI-compatible</td></tr></tbody></table><p>The OpenAI SDK has become the lingua franca — most inference providers offer OpenAI-compatible APIs, meaning a single SDK can target multiple backends by changing the <code>base_url</code>.</p><hr><h2 id="cost-comparison-as-of-mid-2025-per-1m-tokens" tabindex="-1">Cost Comparison (as of mid-2025, per 1M tokens) <a class="header-anchor" href="#cost-comparison-as-of-mid-2025-per-1m-tokens" aria-label="Permalink to &quot;Cost Comparison (as of mid-2025, per 1M tokens)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Model</th><th>Input Cost</th><th>Output Cost</th><th>Cached Input</th><th>Context Window</th></tr></thead><tbody><tr><td>GPT-4o</td><td>$2.50</td><td>$10.00</td><td>$1.25</td><td>128K</td></tr><tr><td>GPT-4o-mini</td><td>$0.15</td><td>$0.60</td><td>$0.075</td><td>128K</td></tr><tr><td>o3</td><td>$10.00</td><td>$40.00</td><td>$2.50</td><td>200K</td></tr><tr><td>o4-mini</td><td>$1.10</td><td>$4.40</td><td>$0.275</td><td>200K</td></tr><tr><td>Claude Sonnet 4</td><td>$3.00</td><td>$15.00</td><td>$0.30</td><td>200K</td></tr><tr><td>Claude Opus 4</td><td>$15.00</td><td>$75.00</td><td>$1.50</td><td>200K</td></tr><tr><td>Claude Haiku 3.5</td><td>$0.80</td><td>$4.00</td><td>$0.08</td><td>200K</td></tr><tr><td>Gemini 2.5 Pro</td><td>$1.25</td><td>$10.00</td><td>—</td><td>1M</td></tr><tr><td>Gemini 2.5 Flash</td><td>$0.15</td><td>$0.60</td><td>—</td><td>1M</td></tr><tr><td>DeepSeek-V3</td><td>$0.27</td><td>$1.10</td><td>$0.07</td><td>128K</td></tr><tr><td>DeepSeek-R1</td><td>$0.55</td><td>$2.19</td><td>$0.14</td><td>128K</td></tr></tbody></table><p><em>Note: Prices are approximate and change frequently. Check provider pricing pages for current rates.</em></p><hr><h2 id="context-window-comparison" tabindex="-1">Context Window Comparison <a class="header-anchor" href="#context-window-comparison" aria-label="Permalink to &quot;Context Window Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Model</th><th>Total Context</th><th>Max Output Tokens</th><th>Effective Input Budget</th></tr></thead><tbody><tr><td>GPT-4o</td><td>128,000</td><td>16,384</td><td>~111,600</td></tr><tr><td>GPT-4o-mini</td><td>128,000</td><td>16,384</td><td>~111,600</td></tr><tr><td>o3</td><td>200,000</td><td>100,000</td><td>~100,000</td></tr><tr><td>o4-mini</td><td>200,000</td><td>100,000</td><td>~100,000</td></tr><tr><td>Claude Sonnet 4</td><td>200,000</td><td>16,000 (default) / 64,000 (extended)</td><td>~136,000-184,000</td></tr><tr><td>Claude Opus 4</td><td>200,000</td><td>16,000 (default) / 32,000 (extended)</td><td>~168,000-184,000</td></tr><tr><td>Gemini 2.5 Pro</td><td>1,048,576</td><td>65,536</td><td>~983,000</td></tr><tr><td>Gemini 2.5 Flash</td><td>1,048,576</td><td>65,536</td><td>~983,000</td></tr><tr><td>DeepSeek-V3</td><td>128,000</td><td>8,192</td><td>~119,800</td></tr><tr><td>Llama 3.1 405B</td><td>128,000</td><td>4,096</td><td>~123,900</td></tr></tbody></table><hr><h2 id="references-and-links" tabindex="-1">References and Links <a class="header-anchor" href="#references-and-links" aria-label="Permalink to &quot;References and Links&quot;">​</a></h2><h3 id="official-api-documentation" tabindex="-1">Official API Documentation <a class="header-anchor" href="#official-api-documentation" aria-label="Permalink to &quot;Official API Documentation&quot;">​</a></h3><ul><li><a href="https://platform.openai.com/docs/api-reference" target="_blank" rel="noreferrer">OpenAI API Reference</a></li><li><a href="https://docs.anthropic.com/en/api" target="_blank" rel="noreferrer">Anthropic API Reference</a></li><li><a href="https://ai.google.dev/api" target="_blank" rel="noreferrer">Google Gemini API Reference</a></li><li><a href="https://platform.deepseek.com/api-docs" target="_blank" rel="noreferrer">DeepSeek API Docs</a></li></ul><h3 id="sdks" tabindex="-1">SDKs <a class="header-anchor" href="#sdks" aria-label="Permalink to &quot;SDKs&quot;">​</a></h3><ul><li><a href="https://github.com/openai/openai-python" target="_blank" rel="noreferrer">openai-python</a> — Official OpenAI Python SDK</li><li><a href="https://github.com/openai/openai-node" target="_blank" rel="noreferrer">openai-node</a> — Official OpenAI TypeScript/Node SDK</li><li><a href="https://github.com/anthropics/anthropic-sdk-python" target="_blank" rel="noreferrer">anthropic-sdk-python</a> — Official Anthropic Python SDK</li><li><a href="https://github.com/anthropics/anthropic-sdk-typescript" target="_blank" rel="noreferrer">anthropic-sdk-typescript</a> — Official Anthropic TypeScript SDK</li><li><a href="https://github.com/googleapis/python-genai" target="_blank" rel="noreferrer">google-genai (Python)</a> — Official Google GenAI Python SDK</li></ul><h3 id="specifications-and-standards" tabindex="-1">Specifications and Standards <a class="header-anchor" href="#specifications-and-standards" aria-label="Permalink to &quot;Specifications and Standards&quot;">​</a></h3><ul><li><a href="https://github.com/openai/openai-openapi" target="_blank" rel="noreferrer">OpenAI API Spec (OpenAPI)</a> — Machine-readable API specification</li><li><a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">Model Context Protocol</a> — Anthropic&#39;s open standard for tool integration</li><li><a href="https://html.spec.whatwg.org/multipage/server-sent-events.html" target="_blank" rel="noreferrer">Server-Sent Events Spec</a> — W3C SSE specification</li></ul><h3 id="community-resources" tabindex="-1">Community Resources <a class="header-anchor" href="#community-resources" aria-label="Permalink to &quot;Community Resources&quot;">​</a></h3><ul><li><a href="https://github.com/BerriAI/litellm" target="_blank" rel="noreferrer">LiteLLM</a> — Unified interface for 100+ LLM providers</li><li><a href="https://github.com/jxnl/instructor" target="_blank" rel="noreferrer">Instructor</a> — Structured output extraction across providers</li><li><a href="https://github.com/openai/tiktoken" target="_blank" rel="noreferrer">tiktoken</a> — OpenAI&#39;s tokenizer library for token counting</li></ul>`,103)])])}const u=e(s,[["render",r]]);export{m as __pageData,u as default};
